import type { ComponentProps, ComponentRef } from 'react';
import { Portal } from '@ark-ui/react/portal';
import { Tooltip as TooltipPrimitive, useTooltip, useTooltipContext } from '@ark-ui/react/tooltip';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Tooltip.module.css';

function TooltipRoot(props: ComponentProps<typeof TooltipPrimitive.Root>) {
  return <TooltipPrimitive.Root {...props} />;
}

function TooltipRootProvider(props: ComponentProps<typeof TooltipPrimitive.RootProvider>) {
  return <TooltipPrimitive.RootProvider {...props} />;
}

function TooltipPortal(props: ComponentProps<typeof Portal>) {
  return <Portal {...props} />;
}

const TooltipTrigger = forwardRef<
  ComponentRef<typeof TooltipPrimitive.Trigger>,
  ComponentProps<typeof TooltipPrimitive.Trigger>
>(function TooltipTrigger({ asChild, className, ...props }, ref) {
  return (
    <TooltipPrimitive.Trigger
      ref={ref}
      data-slot="tooltip-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const TooltipPositioner = forwardRef<
  ComponentRef<typeof TooltipPrimitive.Positioner>,
  ComponentProps<typeof TooltipPrimitive.Positioner>
>(function TooltipPositioner({ className, ...props }, ref) {
  return (
    <TooltipPrimitive.Positioner
      ref={ref}
      data-slot="tooltip-positioner"
      className={clsx(styles.positioner, normalizeClassName(className))}
      {...props}
    />
  );
});

const TooltipContent = forwardRef<
  ComponentRef<typeof TooltipPrimitive.Content>,
  ComponentProps<typeof TooltipPrimitive.Content>
>(function TooltipContent({ className, ...props }, ref) {
  return (
    <TooltipPrimitive.Content
      ref={ref}
      data-slot="tooltip-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const TooltipArrow = forwardRef<
  ComponentRef<typeof TooltipPrimitive.Arrow>,
  ComponentProps<typeof TooltipPrimitive.Arrow>
>(function TooltipArrow({ className, children, ...props }, ref) {
  return (
    <TooltipPrimitive.Arrow
      ref={ref}
      data-slot="tooltip-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <TooltipArrowTip />}
    </TooltipPrimitive.Arrow>
  );
});

const TooltipArrowTip = forwardRef<
  ComponentRef<typeof TooltipPrimitive.ArrowTip>,
  ComponentProps<typeof TooltipPrimitive.ArrowTip>
>(function TooltipArrowTip({ className, ...props }, ref) {
  return (
    <TooltipPrimitive.ArrowTip
      ref={ref}
      data-slot="tooltip-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const TooltipContext = TooltipPrimitive.Context;

const Tooltip = Object.assign(TooltipRoot, {
  Root: TooltipRoot,
  RootProvider: TooltipRootProvider,
  Portal: TooltipPortal,
  Trigger: TooltipTrigger,
  Positioner: TooltipPositioner,
  Content: TooltipContent,
  Arrow: TooltipArrow,
  ArrowTip: TooltipArrowTip,
  Context: TooltipContext,
});

export { Tooltip, useTooltip, useTooltipContext };
export type {
  TooltipOpenChangeDetails,
  TooltipTriggerValueChangeDetails,
  UseTooltipContext,
  UseTooltipProps,
  UseTooltipReturn,
} from '@ark-ui/react/tooltip';

@layer ui.components {
  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--tooltip-trigger-height, var(--size-lg));
    margin: 0;
    padding: var(--tooltip-trigger-padding-y, 0.5rem) var(--tooltip-trigger-padding-x, 0.875rem);
    border: var(--tooltip-trigger-border-width, var(--border-width-sm)) solid
      var(--tooltip-trigger-border-color, var(--color-border));
    border-radius: var(--tooltip-trigger-radius, var(--radius-md));
    background-color: var(--tooltip-trigger-bg, var(--color-background));
    color: var(--tooltip-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--tooltip-trigger-font-size, var(--text-sm));
    line-height: var(--tooltip-trigger-line-height, var(--line-height-text-sm));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--tooltip-transition, var(--transition-default)),
      border-color var(--tooltip-transition, var(--transition-default)),
      color var(--tooltip-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--tooltip-trigger-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-state='open'] {
      background-color: var(
        --tooltip-trigger-bg-active,
        var(--tooltip-trigger-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(--tooltip-focus-ring-width, var(--border-width-sm)) solid
        var(--tooltip-focus-ring-color, var(--color-ring));
      outline-offset: var(--tooltip-focus-ring-offset, -1px);
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--tooltip-disabled-opacity, var(--opacity-disabled));
    }
  }

  .positioner {
    z-index: var(--z-index, var(--z-popup));
    max-width: var(--available-width);
    max-height: var(--available-height);
    outline: 0;
  }

  .content {
    --arrow-background: var(--tooltip-arrow-background, var(--tooltip-bg, var(--color-popover)));
    --arrow-size: var(--tooltip-arrow-size, 0.625rem);

    box-sizing: border-box;
    position: relative;
    z-index: var(--tooltip-z-index, var(--z-popup));
    max-width: min(var(--tooltip-max-width, 20rem), var(--available-width));
    max-height: min(var(--tooltip-max-height, 24rem), var(--available-height, 100dvh));
    padding: var(--tooltip-padding-y, 0.25rem) var(--tooltip-padding-x, 0.5rem);
    border: var(--tooltip-border-width, var(--border-width-sm)) solid
      var(--tooltip-border-color, var(--color-border));
    border-radius: var(--tooltip-radius, var(--radius-md));
    background-color: var(--tooltip-bg, var(--color-popover));
    color: var(--tooltip-color, var(--color-popover-foreground));
    box-shadow: var(--tooltip-shadow, var(--shadow-lg));
    font-size: var(--tooltip-font-size, var(--text-sm));
    line-height: var(--tooltip-line-height, var(--line-height-text-sm));
    text-align: center;
    transform-origin: var(--transform-origin);

    &[data-state='open'] {
      animation: tooltip-content-in var(--tooltip-transition, var(--duration-fast)) ease-out;
    }

    &[data-state='closed'] {
      animation: tooltip-content-out var(--tooltip-transition, var(--duration-fast)) ease-in;
    }

    &[data-instant] {
      animation-duration: 0s;
    }
  }

  .arrow {
    --arrow-background: var(--tooltip-arrow-background, var(--tooltip-bg, var(--color-popover)));
    --arrow-size: var(--tooltip-arrow-size, 0.625rem);
  }

  .arrowTip {
    border-top: var(--tooltip-border-width, var(--border-width-sm)) solid
      var(--tooltip-arrow-stroke-color, var(--tooltip-border-color, var(--color-border)));
    border-left: var(--tooltip-border-width, var(--border-width-sm)) solid
      var(--tooltip-arrow-stroke-color, var(--tooltip-border-color, var(--color-border)));
  }

  @keyframes tooltip-content-in {
    from {
      opacity: var(--tooltip-popup-starting-opacity, 0);
      translate: var(--tooltip-popup-starting-translate-x, 0)
        var(--tooltip-popup-starting-translate-y, 0);
      transform: scale(var(--tooltip-popup-starting-scale, var(--scale-popup)));
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes tooltip-content-out {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(--tooltip-popup-ending-opacity, 0);
      translate: var(--tooltip-popup-ending-translate-x, 0)
        var(--tooltip-popup-ending-translate-y, 0);
      transform: scale(var(--tooltip-popup-ending-scale, var(--scale-popup)));
    }
  }
}

export { Tooltip, useTooltip, useTooltipContext } from './Tooltip';
export type {
  TooltipOpenChangeDetails,
  TooltipTriggerValueChangeDetails,
  UseTooltipContext,
  UseTooltipProps,
  UseTooltipReturn,
} from './Tooltip';
